257â†’+/**
258â†’+ * Tiny event emitter for cross-feature connection signals.
259â†’+ *
260â†’+ * Session actions call emitSendAttemptFailed() when a command rejects
261â†’+ * because the WebSocket is down. The connection store listens and
262â†’+ * immediately escalates to DISCONNECTED state.
263â†’+ */
264â†’+
265â†’+type Listener = () => void;
266â†’+
267â†’+const listeners = new Set<Listener>();
268â†’+
269â†’+export function emitSendAttemptFailed(): void {
270â†’+  for (const fn of listeners) fn();
271â†’+}
272â†’+
273â†’+export function onSendAttemptFailed(cb: Listener): () => void {
