285â†’+/**
286â†’+ * Connection state machine â€” Zustand store.
287â†’+ *
288â†’+ * States:
289â†’+ *   CONNECTED     â†’ healthy, all systems go
290â†’+ *   GRACE_PERIOD  â†’ WS just dropped, wait 2s before showing anything
291â†’+ *   RECONNECTING  â†’ 2-30s, show thin reconnecting bar
292â†’+ *   DISCONNECTED  â†’ 30s+, show full banner, dim content
293â†’+ *
294â†’+ * Escalation shortcuts:
295â†’+ *   - If a sendCommand fails while in GRACE_PERIOD or RECONNECTING,
296â†’+ *     immediately jump to DISCONNECTED (user tried to act).
297â†’+ */
298â†’+
299â†’+import { create } from "zustand";
300â†’+import { forceReconnect } from "@/platform/ws";
301â†’+
302â†’+const GRACE_MS = 2_000;
303â†’+const ESCALATE_MS = 30_000;
304â†’+
305â†’+export type ConnectionState = "connected" | "grace_period" | "reconnecting" | "disconnected";
306â†’+
307â†’+interface ConnectionStore {
308â†’+  state: ConnectionState;
309â†’+  disconnectedAt: number | null;
310â†’+  sendAttemptFailed: boolean;
311â†’+  onConnected: () => void;
312â†’+  onDisconnected: () => void;
313â†’+  markSendAttemptFailed: () => void;
314â†’+  retry: () => void;
315â†’+}
316â†’+
317â†’+// Module-level timer refs (not serializable, don't belong in store state)
318â†’+let graceTimer: ReturnType<typeof setTimeout> | null = null;
319â†’+let escalateTimer: ReturnType<typeof setTimeout> | null = null;
320â†’+
321â†’+function clearTimers() {
322â†’+  if (graceTimer) {
323â†’+    clearTimeout(graceTimer);
324â†’+    graceTimer = null;
325â†’+  }
326â†’+  if (escalateTimer) {
327â†’+    clearTimeout(escalateTimer);
328â†’+    escalateTimer = null;
329â†’+  }
330â†’+}
331â†’+
