new file mode 100644
index 000000000..fb9d0b5ca
--- /dev/null
+++ b/apps/web/src/features/connection/ui/ConnectionOrb.tsx
@@ -0,0 +1,72 @@
+/**
+ * ConnectionOrb â€” ambient connection health indicator for the sidebar footer.
+ *
+ * Always renders (unlike the old BackendStatusIndicator which only showed when disconnected).
+ * Visual states:
+ *   connected    â†’ green dot, static
+ *   grace_period â†’ green dot (unchanged â€” 2s buffer, user sees nothing)
+ *   reconnecting â†’ amber dot with breathing pulse
+ *   disconnected â†’ amber dot with breathing pulse + "Offline" label
+ */
+
+import { AnimatePresence, m, useReducedMotion } from "framer-motion";
+import { match } from "ts-pattern";
+import { cn } from "@/shared/lib/utils";
+import { useConnectionState, type ConnectionState } from "../hooks/useConnectionState";
+
+const EASE_OUT_QUART = [0.165, 0.84, 0.44, 1] as const;
+
+function getAriaLabel(state: ConnectionState): string {
+  return match(state)
+    .with("connected", "grace_period", () => "Connected")
+    .with("reconnecting", () => "Reconnecting")
+    .with("disconnected", () => "Server disconnected")
+    .exhaustive();
+}
+
+export function ConnectionOrb() {
+  const { state } = useConnectionState();
+  const reduceMotion = useReducedMotion();
+
+  const isAmber = state === "reconnecting" || state === "disconnected";
+  const showLabel = state === "disconnected";
+  const showPulse = isAmber && !reduceMotion;
+
+  return (
+    <div
+      className="flex items-center gap-1.5 px-1 py-0.5"
+      role="status"
+      aria-label={getAriaLabel(state)}
+    >
+      <span className="relative flex h-2 w-2 items-center justify-center">
+        {/* Breathing pulse ring */}
+        {showPulse && (
+          <span className="bg-accent-gold absolute inline-flex h-full w-full animate-ping rounded-full opacity-60" />
+        )}
+        {/* Solid dot â€” CSS transition for color (compositor-friendly) */}
+        <span
+          className={cn(
+            "relative inline-flex h-2 w-2 rounded-full transition-colors duration-300",
+            isAmber ? "bg-accent-gold" : "bg-accent-green"
+          )}
+        />
+      </span>
+
+      {/* "Offline" label â€” only in disconnected state */}
+      <AnimatePresence>
+        {showLabel && (
+          <m.span
+            key="connection-label"
+            className="text-text-muted overflow-hidden whitespace-nowrap text-xs"
+            initial={reduceMotion ? false : { opacity: 0, x: -4 }}
+            animate={{ opacity: 1, x: 0 }}
+            exit={reduceMotion ? { opacity: 0 } : { opacity: 0, x: -4 }}
+            transition={{ duration: reduceMotion ? 0 : 0.2, ease: EASE_OUT_QUART }}
+          >
+            Offline
+          </m.span>
+        )}
+      </AnimatePresence>
+    </div>
+  );
+}
diff --git a/apps/web/src/features/connection/ui/ServerOfflinePage.tsx b/apps/web/src/features/connection/ui/ServerOfflinePage.tsx
new file mode 100644
index 000000000..9f58721ec
--- /dev/null
+++ b/apps/web/src/features/connection/ui/ServerOfflinePage.tsx
@@ -0,0 +1,125 @@
+/**
+ * ServerOfflinePage â€” full-page state when the backend is unreachable.
+ *
+ * Replaces the plain "Cannot connect to server" error pages in both
+ * DesktopShell and ServerLayout. Features the warm illustration,
+ * clear copy, and a "Waiting for connection" indicator.
+ *
+ * Two variants:
+ *   "desktop" â€” "Desktop app not detected", shows retry button
+ *   "relay"   â€” "Your computer isn't connected", no retry (relay handles it)
+ */
+
+import { m, useReducedMotion } from "framer-motion";
+import { Button } from "@/components/ui/button";
+import { ConnectionIllustration } from "./ConnectionIllustration";
+
+const EASE_OUT_QUART = [0.165, 0.84, 0.44, 1] as const;
+
+interface ServerOfflinePageProps {
+  onRetry: () => void;
+  variant: "desktop" | "relay";
+}
+
+const COPY = {
+  desktop: {
+    heading: "Desktop app not detected",
+    body: "Open the OpenDevs desktop app to connect this browser session to your agents and workspaces.",
+  },
+  relay: {
+    heading: "Your computer isn't connected",
+    body: "Make sure the OpenDevs desktop app is running on your computer. This page will connect automatically.",
+  },
+} as const;
+
+// Staggered fade-in variants
+const containerVariants = {
+  hidden: {},
+  visible: {
+    transition: { staggerChildren: 0.08 },
+  },
+};
+
+const itemVariants = {
+  hidden: { opacity: 0, y: 12 },
+  visible: {
+    opacity: 1,
+    y: 0,
+    transition: { duration: 0.35, ease: EASE_OUT_QUART },
+  },
+};
+
+export function ServerOfflinePage({ onRetry, variant }: ServerOfflinePageProps) {
+  const copy = COPY[variant];
+  const reduceMotion = useReducedMotion();
+  const variants = reduceMotion ? undefined : itemVariants;
+
+  return (
+    <div className="bg-background flex h-screen w-full items-center justify-center p-6">
+      <m.div
+        className="flex max-w-[380px] flex-col items-center gap-6 text-center"
+        {...(!reduceMotion && {
+          variants: containerVariants,
+          initial: "hidden",
+          animate: "visible",
+        })}
+      >
+        <m.div variants={variants}>
+          <ConnectionIllustration className="w-[260px] opacity-80" />
+        </m.div>
+
+        <m.h1
+          variants={variants}
+          className="text-foreground text-xl font-semibold tracking-tight"
+        >
+          {copy.heading}
+        </m.h1>
+
+        <m.p
+          variants={variants}
+          className="text-muted-foreground max-w-[340px] text-sm leading-relaxed"
+        >
+          {copy.body}
+        </m.p>
+
+        {variant === "desktop" && (
+          <m.div variants={variants}>
+            <Button variant="outline" size="sm" onClick={onRetry}>
+              Try again
+            </Button>
+          </m.div>
+        )}
+
+        <m.div variants={variants} className="flex items-center gap-2">
+          <WaitingDots reduced={reduceMotion} />
+          <span className="text-text-muted text-xs">Waiting for connection</span>
+        </m.div>
+      </m.div>
+    </div>
+  );
+}
+
+/** Three pulsing dots â€” communicates "I'm alive and checking" */
+function WaitingDots({ reduced }: { reduced: boolean | null }) {
+  return (
+    <div className="flex items-center gap-1">
+      {[0, 1, 2].map((i) =>
+        reduced ? (
+          <span key={i} className="bg-text-muted size-1 rounded-full opacity-40" />
+        ) : (
+          <m.span
+            key={i}
+            className="bg-text-muted size-1 rounded-full"
+            animate={{ opacity: [0.2, 0.8, 0.2] }}
+            transition={{
+              duration: 1.5,
+              repeat: Infinity,
+              delay: i * 0.2,
+              ease: "easeInOut",
+            }}
+          />
+        )
+      )}
+    </div>
+  );
+}
